&lt;div class=&quot;row&quot;&gt;
	&lt;div class=&quot;col-sm-12 col-md-12&quot;&gt;&lt;img id=&quot;bor&quot; src=&quot;data/uploads/innerbanner3.jpg&quot; width=&quot;100%&quot; /&gt;&lt;/div&gt;
	&lt;div class=&quot;col-sm-12 col-md-12&quot;&gt;&lt;br /&gt;
		&lt;ul&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Advanced endoscope systems- Upper Gastro scopy, Colonoscopy and ERCP scopy from Olympus Corporation, Japan.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Fully automated laboratory from Rosch, Germany.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Full HD laparoscopy system from Carl Storz.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Full HD laparoscopy system from Stryker, USA.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;ERBE vessel sealing system (Germany) for advanced hepatobiliary work.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;ERBE Argon Plasma Coagulation - APC (Germany) for the control of surgical site bleeding.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Sterrad System (Johnson &amp;amp; Johnson - USA) for sterilization of the surgical instruments.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Networked-computerized outpatient consultation office.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Fully equipped state of the art operation theatre for technically demanding surgeries.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Comprehensive gastro department with OPD, emergency and indoor services.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Complete medical &amp;amp; surgical treatment of digestive system &amp;amp; liver disease &amp;amp; pancreatobiliary diseases&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;First time in region Bariatric Surgery unit for permanent weight loss.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Dedicated modular OT for advance laparoscopic /minimal access surgeries.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;State of art Karl storz and Stryker HD - camera for advance laparoscopy.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Ethicon endosurgery Harmonic scalpel &amp;amp; Erbe Vesselseal device.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Endoscopy suite with Olympus k-170 series for upper Gastro Endoscopy and lower Gastro Colonoscopy - both diagnostic and therapeutic.&lt;/li&gt;
			&lt;li&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;ERCP and all other advanced therapeutic endoscopic procedure with C arm Guidance.&lt;/li&gt;
		&lt;/ul&gt;
	&lt;/div&gt;
